    if name_id is not None:
        user_info['name_id'] = name_id.text
        user_info['name_id_format'] = name_id.get('Format', '')
    
    # Extract attributes
    attributes = {}
    attribute_statements = assertion.findall('.//saml2:AttributeStatement', NAMESPACES)
    
    for attr_statement in attribute_statements:
        for attr in attr_statement.findall('.//saml2:Attribute', NAMESPACES):
            attr_name = attr.get('Name')
            attr_values = []
            
            for attr_value in attr.findall('.//saml2:AttributeValue', NAMESPACES):
                if attr_value.text:
                    attr_values.append(attr_value.text)
            
            if attr_values:
                attributes[attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
    
    user_info['attributes'] = attributes
    
    return user_info

