def saml_metadata(request):
    """
    Generate SAML Service Provider metadata.
    
    Args:
        request: Django HTTP request
    
    Returns:
        HTTP response with XML metadata
    """
    from django.urls import reverse
    
    acs_url = request.build_absolute_uri(reverse('saml_acs'))
    entity_id = getattr(settings, 'SAML_ENTITY_ID', request.build_absolute_uri('/'))
    
    metadata = f"""<?xml version="1.0"?>
<md:EntityDescriptor xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
                     entityID="{entity_id}">
  <md:SPSSODescriptor protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
    <md:AssertionConsumerService Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
                                 Location="{acs_url}"
                                 index="0"/>
  </md:SPSSODescriptor>
</md:EntityDescriptor>"""
    
    return HttpResponse(metadata, content_type='application/xml')